let balance = read_wallet_mapping(db, wallet_address, user_address, BALANCE_MAPPING_SLOT)?;
let lock_until = read_wallet_mapping(db, wallet_address, user_address, LOCK_MAPPING_SLOT)?;
...
let total_required_fees = executor_fee + commitment_fee + inclusion_fee + callback_fee;
let required_lock_until = commit_block.saturating_add(ttl);

if balance < total_required_fees {
    return Err(format!(
        "insufficient RitualWallet balance for short async commitment: balance={balance}, required={total_required_fees}, user={user_address}"
    ));
}
if lock_until < U256::from(required_lock_until) {
    return Err(format!(
        "insufficient RitualWallet lock for short async commitment: lock_until={lock_until}, required={required_lock_until}, user={user_address}"
    ));
}

let original_payer = original_transaction_payer(&original_tx);
verify_wallet_for_commitment(
    &mut db,
    original_payer,
    commitment.precompile_address,
    &commitment.precompile_input,
    commitment.ttl,
    current_block,
)
.map_err(|err| {
    BlockVerificationError::InvalidAsyncCommitment(format!(
        "wallet balance/lock check failed for {}: {err}",
        commitment.origin_tx
    ))
})?;
